            nx, ny = sx + dx, sy + dy
            if not inb(nx, ny) or (nx, ny) in obs_set:
                continue
            d_t = dist2((nx, ny), target)
            d_o = dist2((nx, ny), (ox, oy))
            scored.append((d_t, -d_o, dx, dy))
        if scored:
            return list(min(scored))
    # Fallback: keep away from opponent (or stay if boxed)
    best = None
    for dx, dy in moves:
        nx, ny = sx + dx, sy + dy
        if not inb(nx, ny) or (nx, ny) in obs_set:
            continue
